#\n# @lc app=leetcode id=3462 lang=python3\n#\n# [3462] Maximum Sum With at Most K Elements\n#\n\n# @lc code=start\nclass Solution:\n    def maxSum(self, grid: List[List[int]], limits: List[int], k: int) -> int:\n        all_candidates = []\n        for i in range(len(grid)):\n            if limits[i] > 0:\n                # Sort each row in descending order and take the top 'limits[i]' elements.\n                # This ensures we respect the row-wise limit while picking the largest values.\n                row_sorted = sorted(grid[i], reverse=True)\n                all_candidates.extend(row_sorted[:limits[i]])\n        \n        # Sort all the selected candidates from all rows in descending order.\n        all_candidates.sort(reverse=True)\n        \n        # Since all grid elements are non-negative, the maximum sum of at most 'k' \n        # elements is simply the sum of the top 'k' elements from our candidate list.\n        # The constraint k <= sum(limits) ensures we have at least k candidates.\n        return sum(all_candidates[:k])\n# @lc code=end